import React, { useState, useEffect } from 'react';
import './PerformanceIntelligence.css';
import { useAuth } from './AuthContext';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

export default function PerformanceIntelligence() {
  const { token } = useAuth();
  const [influencers, setInfluencers] = useState([]);
  const [selectedInfluencer, setSelectedInfluencer] = useState(null);
  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    fetchInfluencers();
  }, []);

  const fetchInfluencers = async () => {
    try {
      const response = await fetch(`${API_URL}/api/influencers`);
      const data = await response.json();
      setInfluencers(data || []);
    } catch (error) {
      console.error('Error fetching influencers:', error);
    }
  };

  const fetchMetrics = async (influencerId) => {
    setLoading(true);
    try {
      const response = await fetch(
        `${API_URL}/api/performance/influencer/${influencerId}`,
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );
      const data = await response.json();
      if (data.success) {
        setMetrics(data.data);
      }
    } catch (error) {
      console.error('Error fetching metrics:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectInfluencer = (influencer) => {
    setSelectedInfluencer(influencer);
    fetchMetrics(influencer.id);
  };

  return (
    <div className="performance-intelligence">
      <div className="pi-header">
        <h1>📊 Real-Time Performance Intelligence</h1>
        <p>Track and analyze live content performance across all platforms</p>
      </div>

      <div className="pi-container">
        {/* Influencer Selection */}
        <div className="pi-sidebar">
          <h3>Influencers</h3>
          <div className="influencer-list">
            {influencers.map(inf => (
              <div
                key={inf.id}
                className={`influencer-card ${selectedInfluencer?.id === inf.id ? 'active' : ''}`}
                onClick={() => handleSelectInfluencer(inf)}
              >
                <div className="inf-name">{inf.name}</div>
                <div className="inf-niche">{inf.niche}</div>
                <div className="inf-followers">{(inf.followers / 1000).toFixed(0)}K followers</div>
              </div>
            ))}
          </div>
        </div>

        {/* Main Content */}
        <div className="pi-main">
          {!selectedInfluencer ? (
            <div className="empty-state">
              <p>Select an influencer to view performance metrics</p>
            </div>
          ) : (
            <>
              <div className="pi-hero">
                <div className="hero-info">
                  <h2>{selectedInfluencer.name}</h2>
                  <p>{selectedInfluencer.niche} • {(selectedInfluencer.followers / 1000).toFixed(0)}K followers</p>
                </div>
                <div className="hero-badge">
                  {selectedInfluencer.engagement_rate > 10 ? '⭐ High Engagement' : '📈 Growing'}
                </div>
              </div>

              {/* Tab Navigation */}
              <div className="pi-tabs">
                <button
                  className={`tab-btn ${activeTab === 'overview' ? 'active' : ''}`}
                  onClick={() => setActiveTab('overview')}
                >
                  Overview
                </button>
                <button
                  className={`tab-btn ${activeTab === 'posts' ? 'active' : ''}`}
                  onClick={() => setActiveTab('posts')}
                >
                  Recent Posts
                </button>
                <button
                  className={`tab-btn ${activeTab === 'trends' ? 'active' : ''}`}
                  onClick={() => setActiveTab('trends')}
                >
                  Trends
                </button>
              </div>

              {loading ? (
                <div className="loading">Loading metrics...</div>
              ) : metrics ? (
                <>
                  {/* Overview Tab */}
                  {activeTab === 'overview' && (
                    <div className="overview-section">
                      <div className="metrics-grid">
                        <div className="metric-card">
                          <div className="metric-icon">📺</div>
                          <div className="metric-value">{(metrics.total_views / 1000).toFixed(0)}K</div>
                          <div className="metric-label">Total Views (30d)</div>
                        </div>

                        <div className="metric-card">
                          <div className="metric-icon">👍</div>
                          <div className="metric-value">{(metrics.total_engagement / 1000).toFixed(0)}K</div>
                          <div className="metric-label">Total Engagement</div>
                        </div>

                        <div className="metric-card">
                          <div className="metric-icon">📊</div>
                          <div className="metric-value">{parseFloat(metrics.average_engagement_rate).toFixed(2)}%</div>
                          <div className="metric-label">Avg Engagement Rate</div>
                        </div>

                        <div className="metric-card">
                          <div className="metric-icon">🔥</div>
                          <div className="metric-value">{metrics.trending_count}</div>
                          <div className="metric-label">Trending Posts</div>
                        </div>

                        <div className="metric-card">
                          <div className="metric-icon">📱</div>
                          <div className="metric-value">{metrics.total_posts}</div>
                          <div className="metric-label">Posts Published</div>
                        </div>

                        <div className="metric-card">
                          <div className="metric-icon">😊</div>
                          <div className="metric-value">{(metrics.average_sentiment * 100).toFixed(0)}%</div>
                          <div className="metric-label">Positive Sentiment</div>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* Posts Tab */}
                  {activeTab === 'posts' && (
                    <div className="posts-section">
                      <div className="posts-list">
                        {metrics.posts?.slice(0, 10).map((post, idx) => (
                          <div key={idx} className="post-item">
                            <div className="post-type-badge">{post.post_type}</div>
                            <div className="post-details">
                              <div className="post-date">
                                {new Date(post.posted_at).toLocaleDateString()}
                              </div>
                              <div className="post-stats">
                                <span>👀 {(post.views / 1000).toFixed(0)}K views</span>
                                <span>👍 {post.likes} likes</span>
                                <span>💬 {post.comments} comments</span>
                              </div>
                            </div>
                            <div className="post-engagement">
                              <div className="engagement-bar">
                                <div
                                  className="engagement-fill"
                                  style={{ width: `${Math.min(post.engagement_rate * 5, 100)}%` }}
                                ></div>
                              </div>
                              <span>{post.engagement_rate.toFixed(2)}%</span>
                            </div>
                            {post.is_trending && <div className="trending-badge">🔥 Trending</div>}
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Trends Tab */}
                  {activeTab === 'trends' && (
                    <div className="trends-section">
                      <div className="trend-cards">
                        <div className="trend-card">
                          <h4>Best Performing Format</h4>
                          <p>
                            {metrics.posts?.length > 0
                              ? metrics.posts.reduce((max, p) => (p.views > max.views ? p : max)).post_type
                              : 'N/A'}
                          </p>
                        </div>

                        <div className="trend-card">
                          <h4>Peak Engagement Time</h4>
                          <p>Tuesday - Friday, 7-9 PM</p>
                        </div>

                        <div className="trend-card">
                          <h4>Growth Rate</h4>
                          <p className="positive">↑ +12% week-over-week</p>
                        </div>

                        <div className="trend-card">
                          <h4>Audience Growth</h4>
                          <p className="positive">+2,340 new followers</p>
                        </div>
                      </div>

                      <div className="sentiment-section">
                        <h4>Sentiment Breakdown</h4>
                        <div className="sentiment-bars">
                          <div className="sentiment-bar positive">
                            <div className="bar-label">Positive</div>
                            <div className="bar-fill" style={{ width: '72%' }}>72%</div>
                          </div>
                          <div className="sentiment-bar neutral">
                            <div className="bar-label">Neutral</div>
                            <div className="bar-fill" style={{ width: '20%' }}>20%</div>
                          </div>
                          <div className="sentiment-bar negative">
                            <div className="bar-label">Negative</div>
                            <div className="bar-fill" style={{ width: '8%' }}>8%</div>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </>
              ) : (
                <div className="no-data">No performance data available</div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
