import React, { useEffect, useState } from 'react';
import PerformanceChart from './PerformanceChart';
import './CampaignDetails.css';

function CampaignDetails({ campaign, onClose, token }) {
  const [influencers, setInfluencers] = useState([]);
  const [performanceData, setPerformanceData] = useState([]);
  const [engagementData, setEngagementData] = useState([]);
  const [loading, setLoading] = useState(true);

  const API_URL = process.env.REACT_APP_API_URL || 'https://terra-ser-influence-intelligence-1.onrender.com';

  useEffect(() => {
    if (!campaign || !campaign.id) return;

    const fetchData = async () => {
      try {
        setLoading(true);

        // Fetch campaign influencers
        const influencersRes = await fetch(
          `${API_URL}/api/campaigns/${campaign.id}/influencers`,
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
        const influencersData = await influencersRes.json();
        setInfluencers(Array.isArray(influencersData) ? influencersData : []);

        // Fetch campaign performance metrics
        const performanceRes = await fetch(
          `${API_URL}/api/campaigns/${campaign.id}/performance`,
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
        const performanceJson = await performanceRes.json();
        
        // Transform performance data for charts
        if (Array.isArray(performanceJson)) {
          setPerformanceData(
            performanceJson.map((item, idx) => ({
              name: `Post ${idx + 1}`,
              value: item.likes || 0,
              engagement: item.engagement_rate || 0,
            }))
          );

          setEngagementData(
            performanceJson.map((item, idx) => ({
              name: `Post ${idx + 1}`,
              value: Math.round(item.engagement_rate || 0),
            }))
          );
        } else if (performanceJson && typeof performanceJson === 'object') {
          // Single item response
          setPerformanceData([
            {
              name: campaign.title,
              value: performanceJson.likes || 0,
              engagement: performanceJson.engagement_rate || 0,
            },
          ]);
          setEngagementData([
            {
              name: campaign.title,
              value: Math.round(performanceJson.engagement_rate || 0),
            },
          ]);
        }
      } catch (err) {
        console.error('Error fetching campaign details:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [campaign, token, API_URL]);

  return (
    <div className="campaign-details-overlay" onClick={onClose}>
      <div className="campaign-details-modal" onClick={(e) => e.stopPropagation()}>
        <button className="close-btn" onClick={onClose}>✕</button>

        <div className="details-header">
          <div>
            <h2>{campaign.title}</h2>
            <div className="details-meta">
              <span className="meta-item">
                <strong>Niche:</strong> {campaign.niche}
              </span>
              <span className="meta-item">
                <strong>Budget:</strong> ${campaign.budget || '0.00'}
              </span>
              <span className="meta-item">
                <strong>Status:</strong> <span className="status-badge">{campaign.status}</span>
              </span>
            </div>
          </div>
        </div>

        {loading ? (
          <div className="loading">Loading campaign details...</div>
        ) : (
          <>
            {/* Influencers Section */}
            <section className="details-section">
              <h3>👥 Assigned Influencers</h3>
              {influencers.length === 0 ? (
                <p className="empty-state">No influencers assigned yet</p>
              ) : (
                <div className="influencers-grid">
                  {influencers.map((inf) => (
                    <div key={inf.id} className="influencer-card">
                      <h4>{inf.name}</h4>
                      <div className="influencer-stat">
                        <strong>Followers:</strong> {(inf.followers / 1000).toFixed(1)}K
                      </div>
                      <div className="influencer-stat">
                        <strong>Engagement:</strong> {inf.engagement_rate}%
                      </div>
                      <div className="influencer-stat">
                        <strong>Niche:</strong> {inf.niche}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>

            {/* Performance Charts Section */}
            <section className="details-section">
              <h3>📊 Performance Insights</h3>
              {performanceData.length === 0 ? (
                <p className="empty-state">No performance data available</p>
              ) : (
                <>
                  <PerformanceChart
                    data={performanceData}
                    type="bar"
                    title="📈 Post Likes Performance"
                  />
                  <PerformanceChart
                    data={engagementData}
                    type="line"
                    title="💬 Engagement Rate Trend"
                  />

                  {/* Summary Stats */}
                  <div className="performance-summary">
                    <div className="summary-stat">
                      <span className="stat-label">Avg Engagement</span>
                      <span className="stat-value">
                        {(
                          engagementData.reduce((sum, item) => sum + item.value, 0) /
                          engagementData.length
                        ).toFixed(1)}
                        %
                      </span>
                    </div>
                    <div className="summary-stat">
                      <span className="stat-label">Total Likes</span>
                      <span className="stat-value">
                        {performanceData.reduce((sum, item) => sum + item.value, 0)}
                      </span>
                    </div>
                    <div className="summary-stat">
                      <span className="stat-label">Posts Tracked</span>
                      <span className="stat-value">{performanceData.length}</span>
                    </div>
                  </div>
                </>
              )}
            </section>

            {/* Campaign Details */}
            <section className="details-section">
              <h3>📋 Campaign Details</h3>
              <div className="details-grid">
                <div className="detail-item">
                  <strong>Created:</strong>
                  <span>{new Date(campaign.created_at).toLocaleDateString()}</span>
                </div>
                {campaign.updated_at && (
                  <div className="detail-item">
                    <strong>Last Updated:</strong>
                    <span>{new Date(campaign.updated_at).toLocaleDateString()}</span>
                  </div>
                )}
                <div className="detail-item">
                  <strong>Campaign ID:</strong>
                  <span className="detail-code">{campaign.id}</span>
                </div>
              </div>
            </section>
          </>
        )}
      </div>
    </div>
  );
}

export default CampaignDetails;
