import React, { useState, useEffect } from 'react';
import './BoostAdvisor.css';
import { useAuth } from './AuthContext';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

export default function BoostAdvisor() {
  const { token } = useAuth();
  const [influencers, setInfluencers] = useState([]);
  const [selectedInfluencer, setSelectedInfluencer] = useState(null);
  const [suggestions, setSuggestions] = useState([]);
  const [boostMetrics, setBoostMetrics] = useState(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('all');

  useEffect(() => {
    fetchInfluencers();
  }, []);

  const fetchInfluencers = async () => {
    try {
      const response = await fetch(`${API_URL}/api/influencers`);
      const data = await response.json();
      setInfluencers(data || []);
    } catch (error) {
      console.error('Error fetching influencers:', error);
    }
  };

  const fetchBoostAdvice = async (influencerId) => {
    setLoading(true);
    try {
      const response = await fetch(
        `${API_URL}/api/boost/boost-advice/${influencerId}`,
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );
      const data = await response.json();
      if (data.success) {
        setSuggestions(data.suggestions || []);
      }
    } catch (error) {
      console.error('Error fetching boost advice:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectInfluencer = (influencer) => {
    setSelectedInfluencer(influencer);
    fetchBoostAdvice(influencer.id);
  };

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'high':
        return '#e74c3c';
      case 'medium':
        return '#f39c12';
      case 'low':
        return '#2ecc71';
      default:
        return '#95a5a6';
    }
  };

  const getPriorityIcon = (priority) => {
    switch (priority) {
      case 'high':
        return '🔴';
      case 'medium':
        return '🟡';
      case 'low':
        return '🟢';
      default:
        return '⚪';
    }
  };

  const filteredSuggestions = suggestions.filter(s => {
    if (activeTab === 'pending') return !s.implemented_at;
    if (activeTab === 'implemented') return s.implemented_at;
    return true;
  });

  return (
    <div className="boost-advisor">
      <div className="ba-header">
        <h1>🚀 AI Boost Advisor</h1>
        <p>Get Claude AI recommendations on which posts need boosting</p>
      </div>

      <div className="ba-container">
        {/* Sidebar */}
        <div className="ba-sidebar">
          <h3>Influencers</h3>
          <div className="influencer-list">
            {influencers.map(inf => (
              <div
                key={inf.id}
                className={`influencer-card ${selectedInfluencer?.id === inf.id ? 'active' : ''}`}
                onClick={() => handleSelectInfluencer(inf)}
              >
                <div className="inf-name">{inf.name}</div>
                <div className="inf-niche">{inf.niche}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Main Content */}
        <div className="ba-main">
          {!selectedInfluencer ? (
            <div className="empty-state">
              <p>Select an influencer to view AI boost recommendations</p>
            </div>
          ) : (
            <>
              <div className="ba-hero">
                <div>
                  <h2>{selectedInfluencer.name}</h2>
                  <p>{selectedInfluencer.niche}</p>
                </div>
                <div className="suggestion-badge">
                  {filteredSuggestions.filter(s => s.priority === 'high').length} High Priority
                </div>
              </div>

              {/* Tabs */}
              <div className="ba-tabs">
                <button
                  className={`tab-btn ${activeTab === 'all' ? 'active' : ''}`}
                  onClick={() => setActiveTab('all')}
                >
                  All Suggestions ({suggestions.length})
                </button>
                <button
                  className={`tab-btn ${activeTab === 'pending' ? 'active' : ''}`}
                  onClick={() => setActiveTab('pending')}
                >
                  Pending ({suggestions.filter(s => !s.implemented_at).length})
                </button>
                <button
                  className={`tab-btn ${activeTab === 'implemented' ? 'active' : ''}`}
                  onClick={() => setActiveTab('implemented')}
                >
                  Implemented ({suggestions.filter(s => s.implemented_at).length})
                </button>
              </div>

              {loading ? (
                <div className="loading">Loading AI recommendations...</div>
              ) : filteredSuggestions.length > 0 ? (
                <div className="suggestions-list">
                  {filteredSuggestions.map((suggestion, idx) => (
                    <div key={idx} className="suggestion-card">
                      <div className="suggestion-header">
                        <div className="suggestion-title">
                          <span className="priority-icon">{getPriorityIcon(suggestion.priority)}</span>
                          <span className="status-badge" style={{ background: getPriorityColor(suggestion.priority) }}>
                            {suggestion.priority.toUpperCase()}
                          </span>
                          <span className="recommendation">{suggestion.recommendation}</span>
                        </div>
                        <div className="engagement-score">
                          Current Engagement: <strong>{suggestion.current_engagement_rate?.toFixed(2)}%</strong>
                        </div>
                      </div>

                      <div className="suggestion-metrics">
                        <div className="metric">
                          <span>Platform:</span>
                          <strong>{suggestion.platform}</strong>
                        </div>
                        <div className="metric">
                          <span>Confidence:</span>
                          <strong>{(suggestion.confidence_score * 100).toFixed(0)}%</strong>
                        </div>
                        <div className="metric">
                          <span>Model:</span>
                          <strong>{suggestion.ai_model}</strong>
                        </div>
                      </div>

                      {suggestion.suggestion && (
                        <div className="suggestion-analysis">
                          <h4>AI Analysis:</h4>
                          <p>{suggestion.suggestion.substring(0, 200)}...</p>
                        </div>
                      )}

                      <div className="suggestion-actions">
                        {!suggestion.implemented_at ? (
                          <>
                            <button className="btn-boost">💰 Apply Boost Strategy</button>
                            <button className="btn-dismiss">Dismiss</button>
                          </>
                        ) : (
                          <div className="implemented-badge">
                            ✅ Implemented on {new Date(suggestion.implemented_at).toLocaleDateString()}
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="no-data">
                  {activeTab === 'pending' ? 'No pending boost suggestions' : 'No suggestions available'}
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* Strategy Comparison Modal */}
      <div className="strategy-section">
        <h3>📊 Boost Strategy Comparison</h3>
        <p>AI-recommended strategies with different budget tiers</p>

        <div className="budget-tiers">
          <div className="tier-card">
            <div className="tier-icon">💵</div>
            <div className="tier-name">Budget Boost</div>
            <div className="tier-price">$10</div>
            <ul className="tier-features">
              <li>Targeted ads for 2 days</li>
              <li>~500 additional views</li>
              <li>3-5% engagement boost</li>
            </ul>
            <button className="btn-tier">Select</button>
          </div>

          <div className="tier-card featured">
            <div className="tier-badge">Most Popular</div>
            <div className="tier-icon">💎</div>
            <div className="tier-name">Smart Boost</div>
            <div className="tier-price">$50</div>
            <ul className="tier-features">
              <li>Multi-platform campaigns</li>
              <li>~2,500 additional views</li>
              <li>8-12% engagement boost</li>
              <li>AI-optimized timing</li>
            </ul>
            <button className="btn-tier featured">Select</button>
          </div>

          <div className="tier-card">
            <div className="tier-icon">🚀</div>
            <div className="tier-name">Premium Boost</div>
            <div className="tier-price">$100</div>
            <ul className="tier-features">
              <li>Full campaign optimization</li>
              <li>~5,000 additional views</li>
              <li>15-20% engagement boost</li>
              <li>Influencer collaboration</li>
            </ul>
            <button className="btn-tier">Select</button>
          </div>
        </div>
      </div>
    </div>
  );
}
