import './App.css';
import { AuthProvider, useAuth } from './AuthContext';
import { AdminProvider, useAdmin } from './AdminContext';
import Login from './Login';
import AdminLogin from './AdminLogin';
import AdminDashboard from './AdminDashboard';
import Campaigns from './Campaigns';
import Dashboard from './Dashboard';
import PerformanceIntelligence from './PerformanceIntelligence';
import BoostAdvisor from './BoostAdvisor';
import ImportInfluencer from './ImportInfluencer';
import ReportGenerator from './ReportGenerator';
import { useState } from 'react';

function AppContent() {
  const { token, logout, user } = useAuth();
  const { adminToken, adminUser, adminLogin, adminLogout, isAdminLoggedIn } = useAdmin();
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [showAdminPanel, setShowAdminPanel] = useState(false);

  // Admin Portal
  if (showAdminPanel) {
    if (!adminToken) {
      return (
        <AdminLogin
          onLoginSuccess={(token, user) => {
            adminLogin(token, user);
          }}
        />
      );
    }

    return <AdminDashboard token={adminToken} user={adminUser} onLogout={() => {
      adminLogout();
      setShowAdminPanel(false);
    }} />;
  }

  // User Portal
  if (!token) {
    return (
      <Login />
    );
  }

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard />;
      case 'campaigns':
        return <Campaigns />;
      case 'performance':
        return <PerformanceIntelligence />;
      case 'boost':
        return <BoostAdvisor />;
      case 'import':
        return <ImportInfluencer />;
      case 'reports':
        return <ReportGenerator />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="app-wrapper">
      {/* Main Navigation */}
      <nav className="main-navigation">
        <div className="nav-brand">
          <span className="brand-icon">🎯</span>
          Terra-ser Intelligence
        </div>

        <div className="nav-items">
          <button
            className={`nav-item ${currentPage === 'dashboard' ? 'active' : ''}`}
            onClick={() => setCurrentPage('dashboard')}
          >
            📊 Dashboard
          </button>
          <button
            className={`nav-item ${currentPage === 'campaigns' ? 'active' : ''}`}
            onClick={() => setCurrentPage('campaigns')}
          >
            🎬 Campaigns
          </button>
          <button
            className={`nav-item ${currentPage === 'performance' ? 'active' : ''}`}
            onClick={() => setCurrentPage('performance')}
          >
            📈 Performance
          </button>
          <button
            className={`nav-item ${currentPage === 'boost' ? 'active' : ''}`}
            onClick={() => setCurrentPage('boost')}
          >
            🚀 Boost Advisor
          </button>
          <button
            className={`nav-item ${currentPage === 'import' ? 'active' : ''}`}
            onClick={() => setCurrentPage('import')}
          >
            📥 Import
          </button>
          <button
            className={`nav-item ${currentPage === 'reports' ? 'active' : ''}`}
            onClick={() => setCurrentPage('reports')}
          >
            📄 Reports
          </button>
        </div>

        <div className="nav-controls">
          <button className="btn-admin" onClick={() => setShowAdminPanel(true)}>
            ⚙️ Admin
          </button>
          <button className="btn-logout" onClick={() => {
            logout();
            setCurrentPage('dashboard');
          }}>
            Logout
          </button>
        </div>
      </nav>

      {/* Page Content */}
      <div className="app-content">
        {renderPage()}
      </div>
    </div>
  );
}

function App() {
  return (
    <AuthProvider>
      <AdminProvider>
        <AppContent />
      </AdminProvider>
    </AuthProvider>
  );
}

export default App;
